library(shiny)
library(data.table)

# ── UI ─────────────────────────────────────────────────────────────────────────
ui <- fluidPage(

  tags$head(
    tags$style(HTML("
      body { max-width: 720px; margin: 40px auto; font-family: sans-serif; padding: 0 20px; }
      h2  { color: #2c3e50; }
      .well { background: #f8f9fa; border: 1px solid #dee2e6; border-radius: 6px; padding: 20px; }
      .btn-primary { background-color: #2c7be5; border-color: #2c7be5; width: 100%; margin-top: 10px; }
      .btn-download { background-color: #28a745; border-color: #28a745; color: white;
                      width: 100%; margin-top: 8px; padding: 10px; font-size: 15px;
                      border-radius: 4px; cursor: pointer; border: none; }
      .btn-download:hover { background-color: #218838; }
      .status-box { padding: 12px 16px; border-radius: 4px; margin: 10px 0; }
      .status-ok  { background: #d4edda; color: #155724; }
      .status-err { background: #f8d7da; color: #721c24; }
      .status-inf { background: #d1ecf1; color: #0c5460; }
      hr { border-color: #dee2e6; }
      table { font-size: 12px; width: 100%; overflow-x: auto; display: block; }
    ")),

    # JS: receive TSV string + filename from R, trigger browser download
    tags$script(HTML("
      Shiny.addCustomMessageHandler('download_tsv', function(msg) {
        var blob = new Blob([msg.content], { type: 'text/plain' });
        var url  = URL.createObjectURL(blob);
        var a    = document.createElement('a');
        a.href     = url;
        a.download = msg.filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      });
    "))
  ),

  titlePanel("🪰 DAM Monitor Combiner"),
  p("Upload three Monitor ", code(".txt"), " files. Activity columns (V11–V42) will be
     summed across monitors and exported as a single combined file."),
  hr(),

  # ── Step 1: uploads ──────────────────────────────────────────────────────────
  div(class = "well",
      h4("Step 1 — Upload Monitor files"),
      fluidRow(
        column(4, fileInput("f1", "Monitor 1", accept = ".txt")),
        column(4, fileInput("f2", "Monitor 2", accept = ".txt")),
        column(4, fileInput("f3", "Monitor 3", accept = ".txt"))
      ),
      uiOutput("upload_status")
  ),

  hr(),

  # ── Step 2: run + download ───────────────────────────────────────────────────
  div(class = "well",
      h4("Step 2 — Combine & Download"),
      actionButton("run_btn", "▶  Run Combination", class = "btn btn-primary btn-lg"),
      br(), br(),
      uiOutput("run_status"),
      uiOutput("download_ui"),
      div(
        uiOutput("preview_header"),
        tableOutput("preview_table")
      )
  ),

  hr(),
  tags$small("Demontis Lab · DAM Monitor Combiner · contact your bioinformatics team for support")
)

# ── Server ─────────────────────────────────────────────────────────────────────
server <- function(input, output, session) {

  # ── helpers ──────────────────────────────────────────────────────────────────

  read_monitor <- function(file_info) {
    fread(file_info$datapath, header = FALSE, sep = "\t", colClasses = "character")
  }

  combine_and_sum <- function(dts) {
    nrows <- sapply(dts, nrow)
    if (length(unique(nrows)) > 1) {
      stop(paste(
        "Files have different row counts:", paste(nrows, collapse = ", "),
        "— make sure all three monitors cover the same time window."
      ))
    }
    ncols <- ncol(dts[[1]])
    if (ncols < 42) {
      stop(paste(
        "Expected at least 42 columns but found", ncols,
        "— please check that the files are correct Monitor txt files."
      ))
    }

    # Metadata columns V1–V10 from first file
    result <- copy(dts[[1]][, 1:10, with = FALSE])

    # Activity columns V11–V42: sum numerically across all monitors
    for (col_idx in 11:42) {
      values <- lapply(dts, function(dt) as.numeric(dt[[col_idx]]))
      summed  <- Reduce("+", values)
      result[, paste0("V", col_idx) := as.integer(round(summed))]
    }

    result
  }

  dt_to_tsv_string <- function(dt) {
    # Convert data.table to a TSV string without header or row names
    con <- textConnection("tsv_lines", "w")
    write.table(dt, con, sep = "\t", quote = FALSE,
                row.names = FALSE, col.names = FALSE)
    close(con)
    paste(tsv_lines, collapse = "\n")
  }

  # ── upload status ─────────────────────────────────────────────────────────────
  output$upload_status <- renderUI({
    n <- sum(!is.null(input$f1), !is.null(input$f2), !is.null(input$f3))
    if (n == 3) {
      div(class = "status-box status-ok", "✓ All 3 files uploaded")
    } else {
      div(class = "status-box status-inf",
          sprintf("%d/3 files uploaded — please upload all three Monitor files.", n))
    }
  })

  # ── reactive result ───────────────────────────────────────────────────────────
  result_data <- eventReactive(input$run_btn, {
    req(input$f1, input$f2, input$f3)
    dts <- lapply(list(input$f1, input$f2, input$f3), read_monitor)
    combine_and_sum(dts)
  })

  # ── run status ────────────────────────────────────────────────────────────────
  output$run_status <- renderUI({
    req(input$run_btn)
    tryCatch({
      dt <- result_data()
      div(class = "status-box status-ok",
          sprintf("✓ Done!  %d rows × %d columns combined.", nrow(dt), ncol(dt)))
    }, error = function(e) {
      div(class = "status-box status-err", paste("✗ Error:", conditionMessage(e)))
    })
  })

  # ── download button — triggers JS download via custom message ─────────────────
  output$download_ui <- renderUI({
    req(input$run_btn)
    tryCatch({
      result_data()   # only show if no error
      suggested <- sub("\\.txt$", "_combined.txt", input$f1$name, ignore.case = TRUE)
      tagList(
        tags$button(
          paste("⬇  Download", suggested),
          class   = "btn-download",
          onclick = "Shiny.setInputValue('dl_clicked', Math.random())"
        )
      )
    }, error = function(e) NULL)
  })

  # ── handle download click ─────────────────────────────────────────────────────
  observeEvent(input$dl_clicked, {
    tryCatch({
      dt       <- result_data()
      tsv_str  <- dt_to_tsv_string(dt)
      filename <- sub("\\.txt$", "_combined.txt", input$f1$name, ignore.case = TRUE)
      session$sendCustomMessage("download_tsv", list(
        content  = tsv_str,
        filename = filename
      ))
    }, error = function(e) {
      showNotification(paste("Download error:", conditionMessage(e)), type = "error")
    })
  })

  # ── preview ───────────────────────────────────────────────────────────────────
  output$preview_header <- renderUI({
    req(input$run_btn)
    tryCatch({
      result_data()
      tags$details(tags$summary("Preview first 10 rows"), br())
    }, error = function(e) NULL)
  })

  output$preview_table <- renderTable({
    req(input$run_btn)
    tryCatch({
      head(result_data(), 10)
    }, error = function(e) NULL)
  }, digits = 0, striped = TRUE, hover = TRUE, bordered = TRUE)
}

shinyApp(ui, server)
